export function randomYoon(char: string): string {
  let samples: string[] | undefined;

  if (char === "сѓЃ" || char === "сѓЁ" || char === "сѓЄ") {
    const useDakuten = Math.random() < 0.2;
    samples = useDakuten
      ? ["сЂЇ", "сЂЌ", "сЂА", "сЂФ", "сЂ▓", "сЂ┐", "сѓі"]
      : ["сЂј", "сЂў", "сЂ│", "сЂ┤"];
  } else if (char === "сЃБ" || char === "сЃЦ" || char === "сЃД") {
    const useDakuten = Math.random() < 0.2;
    samples = useDakuten
      ? ["сѓГ", "сѓи", "сЃЂ", "сЃІ", "сЃњ", "сЃЪ", "сЃф"]
      : ["сѓ«", "сѓИ", "сЃЊ", "сЃћ"];

    if (char === "сЃЦ" && useDakuten) {
      samples.push("сЃЄ", "сЃЋ");
    }
  } else if (char === "сѓА") {
    samples = ["сЃё", "сЃЋ", "сЃ┤"];
  } else if (char === "сѓБ") {
    samples = ["сЃё", "сЃє", "сЃЄ", "сЃЋ", "сѓд", "сЃ┤"];
  } else if (char === "сѓД") {
    samples = ["сѓи", "сѓИ", "сЃЂ", "сЃё", "сЃЋ", "сѓд", "сЃ┤"];
  } else if (char === "сѓЕ") {
    samples = ["сѓи", "сЃЋ", "сѓд", "сЃ┤"];
  }

  if (!samples) {
    return char;
  }

  const picked = samples[Math.floor(samples.length * Math.random())];

  return `${picked}${char}`;
}

export function isYoon(char: string): boolean {
  return ["сѓЃ", "сѓЁ", "сѓЄ", "сЃБ", "сЃЦ", "сЃД", "сѓА", "сѓБ", "сѓД", "сѓЕ"].includes(
    char,
  );
}
